def dummy_signature(sig_type):
    order = generator_secp256k1.order()
    r, s = order - 1, order // 2
    return der.sigencode_der(r, s) + bytes_from_int(sig_type)


def fix_input_script(inp, redeem_script):
    """replace dummy signatures with OP_0 and add redeem script for digitaloracle compatibility"""
    dummy = b2h(dummy_signature(1))
    ops1 = []
    for op in opcode_list(inp.script):
        if op == dummy:
            op = 'OP_0'
        ops1.append(op)
    # FIXME hack to add redeem script omitted by pycoin
    ops1.append(b2h(redeem_script))
    inp.script = compile(' '.join(ops1))

Also, the `datetimes` in the example above looks too chaotic, seems like values don't matter. In this case, it's better to just randomly choice values from the list.

Like this:

```
import random

from datetime import datetime, timedelta


def bulk_create_datetimes(diapason=(), number=None, *args, **kwargs):
    dt_objects = []
    try:
        start, end = diapason
    except ValueError:
        end = datetime.now()
        start = end - timedelta(days=7)

    while start <= end:
        start += timedelta(*args, **kwargs)
        dt_objects.append(start)

    if number and len(dt_objects) > number:
        random.shuffle(dt_objects)
        return dt_objects[number]

    return dt_objects

```

