        }
    }
}
```

Looking at it now, I think I prefer the second.

I wasn't able to reproduce the issue with plain zstd. This script generates the same samples as the Python version, and it always generates a dictionary that hashes to `66c76a1caa91c47f5b7eb7c6fb8f509640240232`. There weren't any ASAN, UBSAN, or MSAN failures in my script. There weren't any ASAN or UBSAN failures with `python setup.py test` (but I don't know about MSAN). It looks like the issue might be in python-zstandard.

```c
#include <assert.h>
#include <string.h>
#include <stdio.h>
#include <stdlib.h>
#define ZDICT_STATIC_LINKING_ONLY
#include <zdict.h>
#include <zstd.h>


char const foo[] =
  "foofoofoofoofoofoofoofoo"
  "foofoofoofoofoofoofoofoo"
  "foofoofoofoofoofoofoofoo"
  "foofoofoofoofoofoofoofoo"
  "foofoofoofoofoofoofoofoo"
  "foofoofoofoofoofoofoofoo"
  "foofoofoofoofoofoofoofoo"
  "foofoofoofoofoofoofoofoo";

char const bar[] =
  "barbarbarbarbarbarbarbar"
  "barbarbarbarbarbarbarbar"
  "barbarbarbarbarbarbarbar"
  "barbarbarbarbarbarbarbar"
  "barbarbarbarbarbarbarbar"
  "barbarbarbarbarbarbarbar"
  "barbarbarbarbarbarbarbar"
  "barbarbarbarbarbarbarbar";


char const foobar[] =
  "foobarfoobarfoobarfoobarfoobarfoobarfoobarfoobar"
  "foobarfoobarfoobarfoobarfoobarfoobarfoobarfoobar"
  "foobarfoobarfoobarfoobarfoobarfoobarfoobarfoobar"
  "foobarfoobarfoobarfoobarfoobarfoobarfoobarfoobar"
  "foobarfoobarfoobarfoobarfoobarfoobarfoobarfoobar"
  "foobarfoobarfoobarfoobarfoobarfoobarfoobarfoobar"
  "foobarfoobarfoobarfoobarfoobarfoobarfoobarfoobar"
  "foobarfoobarfoobarfoobarfoobarfoobarfoobarfoobar";

int main(void) {
  size_t const capacity = 8192;
  size_t const numSamples = 128 * 3;
  size_t const samplesSize = 128 * (sizeof(foo) - 1 + sizeof(bar) - 1 + sizeof(foobar) - 1);
  char *const dictionary = (char *)malloc(capacity);
  char *const samples = (char *)malloc(samplesSize);
  size_t *const sampleSizes = (size_t *)malloc(numSamples * sizeof(size_t));
  char *sample = samples;
  size_t *sampleSize = sampleSizes;
  ZDICT_params_t params;
  int ret = 0;
  int i;

  if (!dictionary || !samples || !sampleSizes) {
    ret = 1;
    goto out;
  }

  for (i = 0; i < 128; ++i) {
    memcpy(sample, foo, sizeof(foo) - 1);
    sample += sizeof(foo) - 1;
    *sampleSize++ = sizeof(foo) - 1;

    memcpy(sample, bar, sizeof(bar) - 1);
    sample += sizeof(bar) - 1;
    *sampleSize++ = sizeof(bar) - 1;

    memcpy(sample, foobar, sizeof(foobar) - 1);
    sample += sizeof(foobar) - 1;
    *sampleSize++ = sizeof(foobar) - 1;
  }
  assert(sample == samples + samplesSize);
  assert(sampleSize == sampleSizes + numSamples);

  params.selectivityLevel = 0;
  params.compressionLevel = 0;
  params.notificationLevel = 0;
  params.dictID = 0;

  size_t const size = ZDICT_trainFromBuffer_advanced(dictionary, capacity, samples, sampleSizes, numSamples, params);
  if (ZDICT_isError(size)) {
    fprintf(stderr, "%s\n", ZSTD_getErrorName(size));
    ret = 2;
    goto out;
  }

  fprintf(stderr, "size: %zu\n", size);
  fwrite(dictionary, 1, size, stdout);

out:
  free(dictionary);
  free(samples);
  free(sampleSizes);

  return ret;
}
```

